"use client";

import React, { useEffect, useState } from "react";
import {
  User,
  Mail,
  ShieldCheck,
  Calendar,
  Pencil,
  Package,
  MapPin,
  CheckCircle,
  Clock,
  ChevronRight,
} from "lucide-react";

export default function ProfilePage() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchMyProfile = async () => {
      try {
        const token = localStorage.getItem("accessToken");
        const res = await fetch("http://localhost:5000/user/myProfile", {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) throw new Error("Failed to fetch");
        const result = await res.json();
        setData(result);
      } catch (err) {
        console.error("Fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchMyProfile();
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center gap-3">
          <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-500 font-bold text-sm uppercase tracking-widest">
            Loading Profile
          </p>
        </div>
      </div>
    );
  }

  const { user, stats, recentActivity } = data;

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-12">
      {/* 1. TOP BANNER */}
      <div className="h-48 bg-gradient-to-r from-indigo-600 via-violet-700 to-purple-800 w-full" />

      <div className="max-w-5xl mx-auto px-6">
        {/* HEADER / AVATAR SECTION */}
        <div className="relative -mt-16 flex flex-col md:flex-row md:items-end justify-between gap-6 pb-6 border-b border-slate-200">
          <div className="flex flex-col md:flex-row items-center md:items-end gap-5">
            <div className="w-32 h-32 rounded-[2.5rem] bg-white p-2 shadow-2xl">
              <div className="w-full h-full rounded-[2rem] bg-gradient-to-br from-indigo-500 to-purple-600 text-white flex items-center justify-center text-4xl font-black border-4 border-white">
                {user.name?.[0].toUpperCase()}
              </div>
            </div>
            <div className="text-center md:text-left mb-2">
              <h1 className="text-4xl font-black text-slate-900 tracking-tight leading-tight">
                {user.name}
              </h1>
              <div className="flex items-center gap-2 text-slate-500 mt-1 justify-center md:justify-start font-medium">
                <Mail size={16} className="text-indigo-500" />
                <span className="text-sm">{user.email}</span>
              </div>
            </div>
          </div>

          <button className="flex items-center gap-2 px-6 py-3 bg-white border border-slate-200 text-slate-700 rounded-2xl font-bold shadow-sm hover:shadow-md hover:border-indigo-200 transition-all active:scale-95">
            <Pencil size={18} className="text-indigo-600" />
            Edit Profile
          </button>
        </div>

        {/* 2. MAIN CONTENT GRID */}
        <div className="grid lg:grid-cols-3 gap-8 mt-8">
          {/* LEFT COLUMN: ACCOUNT DETAILS */}
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
              <h3 className="text-lg font-black text-slate-900 mb-6 flex items-center gap-2">
                <ShieldCheck className="w-5 h-5 text-indigo-500" />
                Account Details
              </h3>
              <div className="space-y-6">
                <DetailItem icon={User} label="Full Name" value={user.name} />
                <DetailItem
                  icon={ShieldCheck}
                  label="Account Role"
                  value={user.role}
                  badge
                />
                <DetailItem
                  icon={Calendar}
                  label="Member Since"
                  value={new Date(user.createdAt).toLocaleDateString("en-US", {
                    month: "long",
                    day: "numeric",
                    year: "numeric",
                  })}
                />
                <DetailItem
                  icon={MapPin}
                  label="Campus Location"
                  value="Cumilla University"
                />
              </div>
            </div>
          </div>

          {/* RIGHT COLUMN: STATS & ACTIVITY */}
          <div className="lg:col-span-2 space-y-6">
            {/* STATS CARDS */}
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
              <StatCard
                icon={Package}
                label="Lost Posts"
                value={stats.lost}
                color="rose"
              />
              <StatCard
                icon={MapPin}
                label="Found Posts"
                value={stats.found}
                color="emerald"
              />
              <StatCard
                icon={CheckCircle}
                label="Solved Cases"
                value={stats.solved}
                color="indigo"
              />
            </div>

            {/* RECENT ACTIVITY */}
            <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
              <div className="p-8 border-b border-slate-50 flex justify-between items-center">
                <h3 className="text-xl font-black text-slate-900">
                  Recent Activity
                </h3>
                <span className="px-3 py-1 bg-slate-100 rounded-lg text-xs font-bold text-slate-500 uppercase">
                  Latest {recentActivity.length}
                </span>
              </div>

              <div className="divide-y divide-slate-50">
                {recentActivity.length > 0 ? (
                  recentActivity.map((activity, index) => (
                    <div
                      key={index}
                      className="p-6 hover:bg-slate-50/50 transition-colors flex items-center justify-between group"
                    >
                      <div className="flex items-center gap-4">
                        <div className="w-12 h-12 rounded-2xl bg-indigo-50 flex items-center justify-center text-indigo-600">
                          <Clock size={20} />
                        </div>
                        <div>
                          <p className="text-sm font-black text-slate-800 group-hover:text-indigo-600 transition-colors">
                            {activity.title}
                          </p>
                          <div className="flex items-center gap-3 mt-1">
                            <span className="text-[10px] font-bold uppercase tracking-wider px-2 py-0.5 bg-indigo-100 text-indigo-700 rounded-md">
                              {activity.activityType}
                            </span>
                            <span className="text-xs text-slate-400 font-medium">
                              {new Date(activity.date).toLocaleDateString()}
                            </span>
                          </div>
                        </div>
                      </div>
                      <ChevronRight className="w-5 h-5 text-slate-300 group-hover:text-indigo-400 transition-all group-hover:translate-x-1" />
                    </div>
                  ))
                ) : (
                  <div className="p-12 text-center">
                    <Package className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                    <p className="text-slate-400 font-bold">
                      No recent activity found
                    </p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ===== REUSABLE SUB-COMPONENTS ===== */

function DetailItem({ icon: Icon, label, value, badge }) {
  return (
    <div className="flex gap-4 items-start">
      <div className="p-2 rounded-xl bg-slate-50 text-slate-400">
        <Icon size={18} />
      </div>
      <div>
        <p className="text-[10px] font-black uppercase tracking-[0.15em] text-slate-400 mb-0.5">
          {label}
        </p>
        {badge ? (
          <span className="inline-flex items-center px-3 py-1 rounded-lg text-xs font-black bg-indigo-50 text-indigo-700 border border-indigo-100 uppercase tracking-tight">
            {value}
          </span>
        ) : (
          <p className="text-sm font-bold text-slate-700">{value}</p>
        )}
      </div>
    </div>
  );
}

function StatCard({ icon: Icon, label, value, color }) {
  const colorClasses = {
    rose: "bg-rose-50 text-rose-600 border-rose-100",
    emerald: "bg-emerald-50 text-emerald-600 border-emerald-100",
    indigo: "bg-indigo-50 text-indigo-600 border-indigo-100",
  };

  return (
    <div
      className={`bg-white p-6 rounded-[2rem] border ${colorClasses[color].split(" ")[2]} shadow-sm hover:shadow-xl transition-all duration-300 group`}
    >
      <div
        className={`w-12 h-12 rounded-2xl ${colorClasses[color].split(" ").slice(0, 2).join(" ")} flex items-center justify-center mb-4 group-hover:scale-110 transition-transform`}
      >
        <Icon size={24} />
      </div>
      <p className="text-3xl font-black text-slate-900 tracking-tight">
        {value < 10 ? `0${value}` : value}
      </p>
      <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">
        {label}
      </p>
    </div>
  );
}
